import { useNavigate } from 'react-router-dom';
import Box from '@mui/material/Box';
import Card from '@mui/material/Card';
import CardActionArea from '@mui/material/CardActionArea';
import Typography from '@mui/material/Typography';
import CircularProgress from '@mui/material/CircularProgress';
import ChevronRightIcon from '@mui/icons-material/ChevronRight';
import useVocabStore from '../store/useVocabStore';
import AppBar from '../components/AppBar';
import ProgressChart from '../components/ProgressChart';
import { BRAND_GRADIENT } from '../theme/theme.js';

export default function DashboardScreen() {
  const navigate = useNavigate();
  const globalGroups = useVocabStore(s => s.globalGroups);
  const isLoaded = useVocabStore(s => s.isLoaded);
  const getGroupProgress = useVocabStore(s => s.getGroupProgress);

  if (!isLoaded) {
    return (
      <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: 'background.default' }}>
        <CircularProgress color="primary" />
      </Box>
    );
  }

  function getGlobalProgress(globalGroup) {
    const subGroupIds = globalGroup.subGroupIds || [];
    const totals = { new: 0, learning: 0, mastered: 0, total: 0 };
    subGroupIds.forEach(id => {
      const p = getGroupProgress(id);
      totals.new += p.new;
      totals.learning += p.learning;
      totals.mastered += p.mastered;
      totals.total += p.total;
    });
    return totals;
  }

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: 'background.default', display: 'flex', flexDirection: 'column' }}>
      <AppBar title="Word Groups" />
      <Box sx={{ flex: 1, p: 2, maxWidth: 600, mx: 'auto', width: '100%', display: 'flex', flexDirection: 'column', gap: 1.5 }}>
        {globalGroups.map(group => {
          const progress = getGlobalProgress(group);
          const wordCount = progress.total;
          const allMastered = progress.mastered === wordCount && wordCount > 0;
          return (
            <Card key={group.id} sx={{ overflow: 'hidden' }}>
              <CardActionArea onClick={() => navigate(`/groups/${group.id}`)}>
                <Box sx={{ height: 4, background: BRAND_GRADIENT }} />
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, p: 2 }}>
                  <ProgressChart progress={progress} size={80} />
                  <Box sx={{ flex: 1, minWidth: 0 }}>
                    <Typography variant="subtitle1" fontWeight={600}>
                      {group.displayName}
                    </Typography>
                    <Typography
                      variant="body2"
                      color={allMastered ? 'success.main' : 'text.secondary'}
                      fontWeight={allMastered ? 600 : 400}
                    >
                      {allMastered ? `✓ Mastered all ${wordCount} words` : `${wordCount} words`}
                    </Typography>
                  </Box>
                  <ChevronRightIcon color="action" />
                </Box>
              </CardActionArea>
            </Card>
          );
        })}
      </Box>
    </Box>
  );
}
