import { createTheme } from '@mui/material/styles';

// Flutter brand colors (from lib/theme/constants.dart + lib/models/review.dart)
export const BRAND = {
  gradientStart: '#FFB300',  // amber[600]
  gradientEnd:   '#FFE082',  // amber[200]
  accent:        '#F57C00',  // deep amber — buttons/FAB
  highlight:     '#F65AA3',  // pink
  bookmark:      '#F9A825',  // yellow[800]
};

export const REVIEW_COLORS = {
  new:      '#FFE082',  // amber[200]
  newDark:  '#FFA000',  // amber[700]
  learning: '#AED581',  // lightGreen[300]
  mastered: '#7CB342',  // lightGreen[600]
};

// Reusable gradient strings
// Light: bright amber (#FFB300 → #FFE082)
// Dark:  deep-orange[900] → amber[800] — same hue family, richer & darker
export const BRAND_GRADIENT       = `linear-gradient(to right, ${BRAND.gradientStart}, ${BRAND.gradientEnd})`;
export const BRAND_GRADIENT_DARK  = `linear-gradient(to right, #E65100, #FF8F00)`;

export function createAppTheme(mode = 'light') {
  const isDark = mode === 'dark';
  return createTheme({
    palette: {
      mode,
      primary: {
        main:  BRAND.gradientStart,
        light: BRAND.gradientEnd,
        dark:  BRAND.accent,
        contrastText: '#fff',
      },
      secondary: {
        main: BRAND.accent,
        contrastText: '#fff',
      },
      background: isDark
        ? { default: '#121212', paper: '#1E1E1E' }
        : { default: '#FAFAFA', paper: '#FFFFFF' },
      error:   { main: '#D32F2F' },
      success: { main: REVIEW_COLORS.mastered },
    },
    typography: {
      fontFamily: "'Roboto', system-ui, sans-serif",
    },
    shape: {
      borderRadius: 12,
    },
    components: {
      MuiAppBar: {
        styleOverrides: {
          root: {
            background: isDark ? BRAND_GRADIENT_DARK : BRAND_GRADIENT,
            boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
          },
        },
      },
      MuiCard: {
        styleOverrides: {
          root: {
            borderRadius: 12,
            boxShadow: isDark
              ? '0 2px 8px rgba(0,0,0,0.4)'
              : '0 2px 8px rgba(0,0,0,0.08)',
            transition: 'transform 0.15s ease, box-shadow 0.15s ease',
            '&:hover': {
              transform: 'translateY(-2px)',
              boxShadow: isDark
                ? '0 8px 24px rgba(0,0,0,0.6)'
                : '0 8px 24px rgba(0,0,0,0.12)',
            },
          },
        },
      },
      MuiButton: {
        styleOverrides: {
          root: { borderRadius: 10, textTransform: 'none', fontWeight: 600 },
        },
      },
      MuiIconButton: {
        styleOverrides: {
          root: {
            '&:hover': { backgroundColor: 'rgba(255,255,255,0.2)' },
          },
        },
      },
    },
  });
}

// Default light theme (kept for any direct imports)
export default createAppTheme('light');
