import { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Box from '@mui/material/Box';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import IconButton from '@mui/material/IconButton';
import Avatar from '@mui/material/Avatar';
import MuiAppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import CircularProgress from '@mui/material/CircularProgress';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import BookmarkBorderIcon from '@mui/icons-material/BookmarkBorder';
import VolumeUpIcon from '@mui/icons-material/VolumeUp';
import useVocabStore from '../store/useVocabStore';
import ProgressChart from '../components/ProgressChart';
import WordDefinition from '../components/WordDefinition';
import { getReviewId } from '../store/useVocabStore';
import { BRAND_GRADIENT, REVIEW_COLORS } from '../theme/theme.js';

const REVIEW_LABELS = {
  NEW: 'This is a new word for you.',
  LEARNING4: 'Review this word 4 more times.',
  LEARNING3: 'Review this word 3 more times.',
  LEARNING2: 'Review this word 2 more times.',
  LEARNING1: 'Review this word 1 more time.',
  MASTERED: 'You have mastered this word! 🎉',
};

export default function StudyScreen() {
  const { groupId } = useParams();
  const navigate = useNavigate();

  const activeGroup = useVocabStore(s => s.activeGroup);
  const activeWord = useVocabStore(s => s.activeWord);
  const isShowingDefinition = useVocabStore(s => s.isShowingDefinition);
  const reviewMap = useVocabStore(s => s.reviewMap);
  const bookMarkMap = useVocabStore(s => s.bookMarkMap);
  const preferredLanguage = useVocabStore(s => s.preferredLanguage);
  const revealDefinition = useVocabStore(s => s.revealDefinition);
  const markWord = useVocabStore(s => s.markWord);
  const gotoNextWord = useVocabStore(s => s.gotoNextWord);
  const toggleBookmark = useVocabStore(s => s.toggleBookmark);
  const getGroupProgress = useVocabStore(s => s.getGroupProgress);
  const setActiveGroup = useVocabStore(s => s.setActiveGroup);
  const isLoaded = useVocabStore(s => s.isLoaded);

  // Animation state
  const [exitDir, setExitDir] = useState(null); // 'left' | 'right' | null
  const [wordKey, setWordKey] = useState(0);

  const animateThen = useCallback((direction, action) => {
    if (exitDir) return; // ignore during ongoing animation
    setExitDir(direction);
    setTimeout(() => {
      action();
      setWordKey(k => k + 1);
      setExitDir(null);
    }, 280);
  }, [exitDir]);

  useEffect(() => {
    if (isLoaded && groupId) {
      setActiveGroup(groupId);
    }
  }, [groupId, isLoaded]);

  if (!isLoaded || !activeGroup || activeGroup.id !== groupId) {
    return (
      <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: 'background.default' }}>
        <CircularProgress color="primary" />
      </Box>
    );
  }

  if (!activeWord) {
    return (
      <Box sx={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', p: 4 }}>
        <Typography color="text.secondary">No words in this group.</Typography>
        <Button onClick={() => navigate(-1)} sx={{ mt: 2 }} color="primary">Go back</Button>
      </Box>
    );
  }

  const reviewId = getReviewId(activeGroup, activeWord);
  const reviewState = reviewMap[reviewId] || 'NEW';
  const isBookmarked = bookMarkMap[activeWord.id];
  const progress = getGroupProgress(groupId);
  const translation = activeWord.definitions?.[0]?.otherLanguages?.[preferredLanguage] || '';

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: 'background.default', display: 'flex', flexDirection: 'column' }}>
      <MuiAppBar position="static" sx={{ background: BRAND_GRADIENT }}>
        <Toolbar>
          <IconButton
            edge="start"
            color="inherit"
            onClick={() => navigate(-1)}
            aria-label="Go back"
            sx={{ mr: 1 }}
          >
            <ArrowBackIcon />
          </IconButton>
          <Typography variant="h6" fontWeight={600} sx={{ flex: 1 }}>
            {activeGroup.displayName}
          </Typography>
        </Toolbar>
      </MuiAppBar>

      <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', p: 2, maxWidth: 600, mx: 'auto', width: '100%' }}>
        {/* Word Card */}
        <Card
          key={wordKey}
          sx={{
            mb: 2, flex: 1,
            animation: exitDir === 'right'
              ? 'wordExitRight 0.28s ease forwards'
              : exitDir === 'left'
              ? 'wordExitLeft 0.28s ease forwards'
              : 'wordEnter 0.3s cubic-bezier(0.22, 1, 0.36, 1)',
          }}
        >
          <CardContent>
            <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', mb: 1 }}>
              <Typography variant="h2" fontWeight="bold" sx={{ flex: 1, fontSize: '2.5rem' }}>
                {activeWord.wordText}
              </Typography>
              <Button
                onClick={() => toggleBookmark(activeWord)}
                color="warning"
                size="small"
                startIcon={isBookmarked ? <BookmarkIcon /> : <BookmarkBorderIcon />}
                sx={{ ml: 1, flexShrink: 0, textTransform: 'none' }}
              >
                {isBookmarked ? 'Bookmarked' : 'Bookmark'}
              </Button>
            </Box>

            {/* Syllable / phonetic */}
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, color: 'text.secondary' }}>
              <VolumeUpIcon color="primary" fontSize="small" />
              <Typography variant="body2">{activeWord.syllable}</Typography>
              <Typography variant="body2" color="text.disabled">{activeWord.phoneticScript}</Typography>
            </Box>

            {!isShowingDefinition ? (
              <Typography variant="body2" color="text.secondary" fontStyle="italic">
                {REVIEW_LABELS[reviewState]}
              </Typography>
            ) : (
              <>
                {translation && (
                  <Typography fontWeight={500} color="primary.dark" sx={{ mb: 1.5 }}>
                    {translation}
                  </Typography>
                )}
                <WordDefinition definitions={activeWord.definitions} />
              </>
            )}
          </CardContent>
        </Card>

        {/* Action Buttons */}
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5, mb: 2 }}>
          {!isShowingDefinition ? (
            <Box sx={{ display: 'flex', gap: 1.5 }}>
              <Button
                variant="contained"
                color="error"
                sx={{ flex: 1 }}
                disabled={!!exitDir}
                onClick={() => animateThen('left', () => markWord(false))}
              >
                🤨 I don't know this
              </Button>
              <Button
                variant="contained"
                color="success"
                sx={{ flex: 1 }}
                disabled={!!exitDir}
                onClick={() => animateThen('right', () => markWord(true))}
              >
                👍 I know this
              </Button>
            </Box>
          ) : (
            <Button
              variant="contained"
              color="primary"
              fullWidth
              disabled={!!exitDir}
              onClick={() => animateThen('right', () => gotoNextWord())}
            >
              Next Word →
            </Button>
          )}
          {!isShowingDefinition && (
            <Button
              variant="text"
              color="primary"
              fullWidth
              onClick={revealDefinition}
            >
              Show definition
            </Button>
          )}
        </Box>

        {/* Progress Card */}
        <Card>
          <CardContent sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <ProgressChart progress={progress} size={120} />
            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 0.75 }}>
              {[
                { label: 'New', value: progress.new, color: REVIEW_COLORS.new },
                { label: 'Learning', value: progress.learning, color: REVIEW_COLORS.learning },
                { label: 'Mastered', value: progress.mastered, color: REVIEW_COLORS.mastered },
              ].map(({ label, value, color }) => (
                <Box key={label} sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <Avatar sx={{ width: 12, height: 12, bgcolor: color, borderRadius: 1 }}>{null}</Avatar>
                  <Typography variant="body2" color="text.secondary">
                    {label}: {value}
                  </Typography>
                </Box>
              ))}
            </Box>
          </CardContent>
        </Card>
      </Box>
    </Box>
  );
}
