import { useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import useVocabStore from './store/useVocabStore';
import SplashScreen from './screens/SplashScreen';
import DashboardScreen from './screens/DashboardScreen';
import SubGroupsScreen from './screens/SubGroupsScreen';
import StudyScreen from './screens/StudyScreen';
import BookmarksScreen from './screens/BookmarksScreen';
import SearchScreen from './screens/SearchScreen';
import AboutScreen from './screens/AboutScreen';
import InstallPrompt from './components/InstallPrompt';

export default function App() {
  const initApp = useVocabStore(s => s.initApp);

  // Always load data on startup regardless of which route is active.
  // SplashScreen also calls this — it's idempotent.
  useEffect(() => {
    initApp();
  }, []);

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<SplashScreen />} />
        <Route path="/dashboard" element={<DashboardScreen />} />
        <Route path="/groups/:globalGroupId" element={<SubGroupsScreen />} />
        <Route path="/study/:groupId" element={<StudyScreen />} />
        <Route path="/bookmarks" element={<BookmarksScreen />} />
        <Route path="/search" element={<SearchScreen />} />
        <Route path="/about" element={<AboutScreen />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
      <InstallPrompt />
    </HashRouter>
  );
}
