import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import MuiAppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import IconButton from '@mui/material/IconButton';
import Typography from '@mui/material/Typography';
import Drawer from '@mui/material/Drawer';
import Box from '@mui/material/Box';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ListItemButton from '@mui/material/ListItemButton';
import ListItemIcon from '@mui/material/ListItemIcon';
import ListItemText from '@mui/material/ListItemText';
import MenuIcon from '@mui/icons-material/Menu';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import BookmarkBorderIcon from '@mui/icons-material/BookmarkBorder';
import SearchIcon from '@mui/icons-material/Search';
import CloseIcon from '@mui/icons-material/Close';
import InfoOutlinedIcon from '@mui/icons-material/InfoOutlined';
import DarkModeIcon from '@mui/icons-material/DarkMode';
import LightModeIcon from '@mui/icons-material/LightMode';
import SettingsBrightnessIcon from '@mui/icons-material/SettingsBrightness';
import Tooltip from '@mui/material/Tooltip';
import { BRAND_GRADIENT, BRAND_GRADIENT_DARK } from '../theme/theme.js';
import { useThemeMode } from '../theme/ThemeContext.jsx';

const DRAWER_WIDTH = 280;

const NAV_ITEMS = [
  { to: '/bookmarks', label: 'Bookmarks', Icon: BookmarkBorderIcon },
  { to: '/search',    label: 'Search Words', Icon: SearchIcon },
  { to: '/about',     label: 'About',      Icon: InfoOutlinedIcon },
];

export default function AppBar({ title, onBack }) {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const navigate = useNavigate();
  const { preference, mode, cycleTheme } = useThemeMode();

  const THEME_ICON = { light: <LightModeIcon />, dark: <DarkModeIcon />, auto: <SettingsBrightnessIcon /> };
  const THEME_LABEL = { light: 'Light mode', dark: 'Dark mode', auto: 'Auto (system)' };

  return (
    <>
      <MuiAppBar position="static">
        <Toolbar>
          {onBack ? (
            <IconButton
              edge="start"
              color="inherit"
              onClick={onBack}
              aria-label="Go back"
              sx={{ mr: 1 }}
            >
              <ArrowBackIcon />
            </IconButton>
          ) : (
            <IconButton
              edge="start"
              color="inherit"
              onClick={() => setDrawerOpen(true)}
              aria-label="Open menu"
              sx={{ mr: 1 }}
            >
              <MenuIcon />
            </IconButton>
          )}

          <Typography variant="h6" sx={{ flexGrow: 1, fontWeight: 600 }}>
            {title}
          </Typography>

          <Tooltip title={THEME_LABEL[preference]}>
            <IconButton
              color="inherit"
              onClick={cycleTheme}
              aria-label="Cycle theme"
            >
              {THEME_ICON[preference]}
            </IconButton>
          </Tooltip>
          <IconButton
            color="inherit"
            onClick={() => navigate('/bookmarks')}
            aria-label="Bookmarks"
          >
            <BookmarkBorderIcon />
          </IconButton>
          <IconButton
            color="inherit"
            onClick={() => navigate('/search')}
            aria-label="Search"
          >
            <SearchIcon />
          </IconButton>
        </Toolbar>
      </MuiAppBar>

      <Drawer
        anchor="left"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
        PaperProps={{ sx: { width: DRAWER_WIDTH } }}
      >
        {/* Drawer header */}
        <Box
          sx={{
            background: mode === 'dark' ? BRAND_GRADIENT_DARK : BRAND_GRADIENT,
            p: 2,
            color: 'white',
            display: 'flex',
            alignItems: 'flex-start',
            justifyContent: 'space-between',
          }}
        >
          <Box>
            <Typography variant="h6" fontWeight="bold">Vocabulary Builder</Typography>
            <Typography variant="body2" sx={{ opacity: 0.8, mt: 0.5 }}>by English House</Typography>
          </Box>
          <IconButton
            color="inherit"
            onClick={() => setDrawerOpen(false)}
            aria-label="Close menu"
            size="small"
          >
            <CloseIcon />
          </IconButton>
        </Box>

        {/* Nav links */}
        <List disablePadding>
          {NAV_ITEMS.map(({ to, label, Icon }) => (
            <ListItem key={to} disablePadding divider>
              <ListItemButton
                onClick={() => { setDrawerOpen(false); navigate(to); }}
              >
                <ListItemIcon sx={{ color: 'primary.main', minWidth: 40 }}>
                  <Icon />
                </ListItemIcon>
                <ListItemText primary={label} />
              </ListItemButton>
            </ListItem>
          ))}
        </List>
      </Drawer>
    </>
  );
}
