import { useNavigate } from 'react-router-dom';
import Box from '@mui/material/Box';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ListItemText from '@mui/material/ListItemText';
import ListItemSecondaryAction from '@mui/material/ListItemSecondaryAction';
import IconButton from '@mui/material/IconButton';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import BookmarkBorderIcon from '@mui/icons-material/BookmarkBorder';
import useVocabStore from '../store/useVocabStore';
import AppBar from '../components/AppBar';
import WordDefinition from '../components/WordDefinition';
import { BRAND } from '../theme/theme.js';

export default function BookmarksScreen() {
  const navigate = useNavigate();
  const getBookmarkedWords = useVocabStore(s => s.getBookmarkedWords);
  const toggleBookmark = useVocabStore(s => s.toggleBookmark);
  const preferredLanguage = useVocabStore(s => s.preferredLanguage);

  const words = getBookmarkedWords();

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: 'background.default', display: 'flex', flexDirection: 'column' }}>
      <AppBar
        title={`Bookmarks${words.length ? ` (${words.length})` : ''}`}
        onBack={() => navigate(-1)}
      />

      <Box sx={{ flex: 1, maxWidth: 600, mx: 'auto', width: '100%' }}>
        {words.length === 0 ? (
          <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: 256, gap: 1.5, color: 'text.disabled' }}>
            <BookmarkBorderIcon sx={{ fontSize: 64, opacity: 0.3 }} />
            <Typography color="text.disabled">No words bookmarked yet</Typography>
          </Box>
        ) : (
          <List disablePadding>
            {words.map((word, idx) => {
              const translation = word.definitions?.[0]?.otherLanguages?.[preferredLanguage] || '';
              return (
                <Box key={word.id}>
                  <ListItem alignItems="flex-start" sx={{ bgcolor: 'background.paper', px: 2, py: 1.5 }}>
                    <ListItemText
                      disableTypography
                      primary={
                        <Typography variant="h6" fontWeight={700}>
                          {word.wordText}
                        </Typography>
                      }
                      secondary={
                        <Box>
                          {translation && (
                            <Typography variant="body2" fontWeight={500} sx={{ color: BRAND.accent, mb: 1 }}>
                              {translation}
                            </Typography>
                          )}
                          <WordDefinition definitions={word.definitions} />
                        </Box>
                      }
                    />
                    <ListItemSecondaryAction>
                      <IconButton
                        edge="end"
                        color="warning"
                        onClick={() => toggleBookmark(word)}
                        aria-label="Remove bookmark"
                      >
                        <BookmarkIcon />
                      </IconButton>
                    </ListItemSecondaryAction>
                  </ListItem>
                  {idx < words.length - 1 && <Divider />}
                </Box>
              );
            })}
          </List>
        )}
      </Box>
    </Box>
  );
}
