import { createContext, useContext, useState, useMemo, useEffect } from 'react';
import { ThemeProvider, CssBaseline } from '@mui/material';
import { createAppTheme } from './theme.js';

const ThemeContext = createContext({ preference: 'auto', mode: 'light', cycleTheme: () => {} });

export const useThemeMode = () => useContext(ThemeContext);

const systemPrefers = () =>
  window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';

const CYCLE = { light: 'dark', dark: 'auto', auto: 'light' };

export function AppThemeProvider({ children }) {
  const [preference, setPreference] = useState(
    () => localStorage.getItem('themeMode') || 'auto'
  );

  const [systemMode, setSystemMode] = useState(systemPrefers);

  // Track OS preference changes
  useEffect(() => {
    const mq = window.matchMedia('(prefers-color-scheme: dark)');
    const handler = (e) => setSystemMode(e.matches ? 'dark' : 'light');
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  // Resolved mode used by theme
  const mode = preference === 'auto' ? systemMode : preference;

  const theme = useMemo(() => createAppTheme(mode), [mode]);

  const cycleTheme = () => {
    setPreference(p => {
      const next = CYCLE[p];
      if (next === 'auto') {
        localStorage.removeItem('themeMode');
      } else {
        localStorage.setItem('themeMode', next);
      }
      return next;
    });
  };

  return (
    <ThemeContext.Provider value={{ preference, mode, cycleTheme }}>
      <ThemeProvider theme={theme}>
        <CssBaseline />
        {children}
      </ThemeProvider>
    </ThemeContext.Provider>
  );
}
