import { REVIEW_COLORS } from '../theme/theme.js';
import { useThemeMode } from '../theme/ThemeContext.jsx';
const COLORS = REVIEW_COLORS;

// Renders arc path data for a donut slice.
function describeArc(cx, cy, r, startAngle, endAngle) {
  const toRad = (deg) => (deg - 90) * (Math.PI / 180);
  const x1 = cx + r * Math.cos(toRad(startAngle));
  const y1 = cy + r * Math.sin(toRad(startAngle));
  const x2 = cx + r * Math.cos(toRad(endAngle));
  const y2 = cy + r * Math.sin(toRad(endAngle));
  const largeArc = endAngle - startAngle > 180 ? 1 : 0;
  return `M ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2}`;
}

export default function ProgressChart({ progress, size = 100 }) {
  const { mode } = useThemeMode();
  const { new: n, learning, mastered } = progress;
  const total = (n || 0) + (learning || 0) + (mastered || 0) || 1;
  const masteredPct = Math.round(((mastered || 0) / total) * 100);

  const slices = [
    { value: n || 0,        color: COLORS.new },
    { value: learning || 0, color: COLORS.learning },
    { value: mastered || 0, color: COLORS.mastered },
  ].filter(s => s.value > 0);

  if (slices.length === 0) slices.push({ value: 1, color: COLORS.new });

  const cx = size / 2;
  const cy = size / 2;
  const outerR = size * 0.46;
  const innerR = size * 0.28;
  const strokeW = outerR - innerR;
  const r = (outerR + innerR) / 2;
  const circumference = 2 * Math.PI * r;

  let cumulative = 0;
  return (
    <svg width={size} height={size}>
      {slices.map((slice, i) => {
        const fraction = slice.value / total;
        const dash = fraction * circumference;
        const gap = circumference - dash;
        const rotation = (cumulative / total) * 360 - 90;
        cumulative += slice.value;
        return (
          <circle
            key={i}
            cx={cx} cy={cy} r={r}
            fill="none"
            stroke={slice.color}
            strokeWidth={strokeW}
            strokeDasharray={`${dash} ${gap}`}
            transform={`rotate(${rotation} ${cx} ${cy})`}
          />
        );
      })}
      {/* Center label: mastered % */}
      <text
        x={cx} y={cy}
        textAnchor="middle"
        dominantBaseline="central"
        fontSize={size * 0.2}
        fontWeight="bold"
        fill={mode === 'dark' ? '#FFFFFF' : '#5D4037'}
      >
        {masteredPct}%
      </text>
    </svg>
  );
}
