import { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import useVocabStore from '../store/useVocabStore';

export default function SplashScreen() {
  const navigate = useNavigate();
  const initApp = useVocabStore(s => s.initApp);

  useEffect(() => {
    initApp().then(() => {
      setTimeout(() => navigate('/dashboard', { replace: true }), 1000);
    });
  }, []);

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 2,
        background: 'radial-gradient(circle, #FFE082 0%, #FFB300 60%, #F57C00 100%)',
      }}
    >
      {/* App icon */}
      <Box
        sx={{
          width: 80,
          height: 80,
          borderRadius: 4,
          bgcolor: 'rgba(255,255,255,0.3)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          boxShadow: 3,
        }}
      >
        <img
          src={`${import.meta.env.BASE_URL}favicon.svg`}
          alt="Deep Vocab"
          style={{ width: 48, height: 48 }}
        />
      </Box>

      <Typography variant="h4" color="white" fontWeight="bold">
        Deep Vocab
      </Typography>
      <Typography variant="body2" sx={{ color: 'rgba(255,255,255,0.8)', mt: -1 }}>
        by English House
      </Typography>

      {/* Cube grid spinner */}
      <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '6px', mt: 2 }}>
        {[...Array(9)].map((_, i) => (
          <Box
            key={i}
            sx={{ width: 16, height: 16, bgcolor: 'white', borderRadius: 0.5 }}
            style={{ animation: `cubeScale 1.2s ease-in-out ${i * 0.13}s infinite` }}
          />
        ))}
      </Box>
    </Box>
  );
}
