import { create } from 'zustand';
import { persist } from 'zustand/middleware';

// Loads from the local CSV by default.
// If VITE_REMOTE_DATA_URL is set in .env, that URL is used instead.
const REMOTE_URL = import.meta.env.VITE_REMOTE_DATA_URL;
const DATA_URL = REMOTE_URL ? REMOTE_URL.trim() : `${import.meta.env.BASE_URL}vocab-data.csv`;

// Parse a raw CSV string into an array of objects keyed by header row.
function parseCsv(text) {
  const lines = text.trim().split('\n');
  const headers = splitCsvRow(lines[0]);
  return lines.slice(1).map(line => {
    const values = splitCsvRow(line);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = values[i] ?? ''; });
    return obj;
  });
}

// Splits a single CSV row respecting quoted fields (RFC 4180).
function splitCsvRow(row) {
  const fields = [];
  let cur = '';
  let inQuotes = false;
  for (let i = 0; i < row.length; i++) {
    const ch = row[i];
    if (inQuotes) {
      if (ch === '"' && row[i + 1] === '"') { cur += '"'; i++; }
      else if (ch === '"') { inQuotes = false; }
      else { cur += ch; }
    } else {
      if (ch === '"') { inQuotes = true; }
      else if (ch === ',') { fields.push(cur); cur = ''; }
      else { cur += ch; }
    }
  }
  fields.push(cur);
  return fields;
}

// Build the hierarchical app data (groups, globalGroups, words) from flat CSV rows.
function csvToAppData(rows) {
  const dayGroupChildren = {};   // "WEEK1-DAY2" -> [wordText, ...]
  const weekGroupChildren = {};  // "WEEK1"       -> [wordText, ...]

  const words = rows.map(row => {
    const weekNum = parseInt(row.weekNumber);
    const dayNum = parseInt(row.dayNumber);

    const dayGroupId = dayNum > 0 ? `WEEK${weekNum}-DAY${dayNum}` : null;
    const weekGroupId = `WEEK${weekNum}`;

    if (dayGroupId) {
      if (!dayGroupChildren[dayGroupId]) dayGroupChildren[dayGroupId] = [];
      dayGroupChildren[dayGroupId].push(row.wordText);
    }
    if (!weekGroupChildren[weekGroupId]) weekGroupChildren[weekGroupId] = [];
    weekGroupChildren[weekGroupId].push(row.wordText);

    const groupIds = dayGroupId ? [weekGroupId, dayGroupId] : [weekGroupId];

    return {
      id: row.wordText,
      wordText: row.wordText,
      phoneticScript: row.phoneticScript,
      syllable: row.syllable,
      bookMarkId: dayGroupId
        ? `${dayGroupId}-${row.wordText}`
        : `${weekGroupId}-${row.wordText}`,
      groupIds,
      tags: groupIds,
      definitions: [{
        type: row.partOfSpeech,
        definitionText: row.definition,
        examples: [row.example1, row.example2].filter(Boolean),
        synonyms: [row.synonym1, row.synonym2, row.synonym3, row.synonym4].filter(Boolean),
        otherLanguages: {
          telugu: row.telugu,
          tamil: row.tamil,
          hindi: row.hindi,
          malayalam: row.malayalam,
        },
      }],
    };
  });

  // Build day groups
  const dayGroups = Object.entries(dayGroupChildren).map(([id, children]) => {
    const m = id.match(/^WEEK(\d+)-DAY(\d+)$/);
    return { id, name: id, displayName: id, globalGroupId: `WEEK${m[1]}-GLOBAL`, children };
  });

  // Build week summary groups
  const weekGroups = Object.entries(weekGroupChildren).map(([id, children]) => {
    const m = id.match(/^WEEK(\d+)$/);
    return { id, name: id, displayName: `${id} Assessment`, globalGroupId: `WEEK${m[1]}-GLOBAL`, children };
  });

  const groups = [...dayGroups, ...weekGroups];

  // Build global groups ordered by week number
  const weekNumbers = [...new Set(rows.map(r => parseInt(r.weekNumber)))].sort((a, b) => a - b);
  const globalGroups = weekNumbers.map(n => {
    const subGroupIds = [1, 2, 3, 4, 5]
      .filter(d => dayGroupChildren[`WEEK${n}-DAY${d}`])
      .map(d => `WEEK${n}-DAY${d}`)
      .concat([`WEEK${n}`]);
    return { id: `WEEK${n}-GLOBAL`, displayName: `Week${n}`, subGroupIds };
  });

  return { groups, globalGroups, words };
}

// Review state progression
const REVIEW_STATES = ['NEW', 'LEARNING4', 'LEARNING3', 'LEARNING2', 'LEARNING1', 'MASTERED'];

export function getReviewId(group, word) {
  return group.globalGroupId + group.id + word.wordText;
}

function getReviewState(reviewMap, group, word) {
  return reviewMap[getReviewId(group, word)] || 'NEW';
}

function computeProgress(group, words, reviewMap) {
  let newCount = 0, learningCount = 0, masteredCount = 0;
  const groupWords = words.filter(w => group.children?.includes(w.id));
  for (const word of groupWords) {
    const state = reviewMap[getReviewId(group, word)] || 'NEW';
    if (state === 'NEW') newCount++;
    else if (state === 'MASTERED') masteredCount++;
    else learningCount++;
  }
  return { new: newCount, learning: learningCount, mastered: masteredCount, total: groupWords.length };
}

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Persistent slice: reviewMap, bookMarkMap, preferredLanguage, dataVersion
const persistedStore = persist(
  (set, get) => ({
    reviewMap: {},
    bookMarkMap: {},
    preferredLanguage: 'telugu',
    dataVersion: null,

    // Non-persisted runtime state (will be reset on load but stored here for convenience)
    groups: [],
    globalGroups: [],
    groupsMap: {},
    wordsMap: {},
    allWords: [],
    activeGroup: null,
    activeWord: null,
    isShowingDefinition: false,
    isLoaded: false,

    setPreferredLanguage: (lang) => set({ preferredLanguage: lang }),

    toggleBookmark: (word) => {
      const { bookMarkMap } = get();
      const updated = { ...bookMarkMap, [word.id]: !bookMarkMap[word.id] };
      set({ bookMarkMap: updated });
    },

    initApp: async () => {
      try {
        const res = await fetch(DATA_URL);
        const csvText = await res.text();

        // Use ETag / last-modified as version — fall back to byte length
        const version = res.headers.get('last-modified') || String(csvText.length);
        const { dataVersion: cachedVersion } = get();

        if (version !== cachedVersion || !get().isLoaded) {
          const rows = parseCsv(csvText);
          const { groups, globalGroups, words } = csvToAppData(rows);

          const groupsMap = {};
          groups.forEach(g => { groupsMap[g.id] = g; });
          const wordsMap = {};
          words.forEach(w => { wordsMap[w.id] = w; });

          set({
            dataVersion: version,
            groups,
            globalGroups,
            groupsMap,
            wordsMap,
            allWords: words,
            isLoaded: true,
          });
        } else {
          set({ isLoaded: true });
        }
      } catch (e) {
        // Use cached data if available
        set({ isLoaded: true });
      }
    },

    setActiveGroup: (groupId) => {
      const { groupsMap, allWords, reviewMap } = get();
      const group = groupsMap[groupId];
      if (!group) return;

      const groupWords = allWords.filter(w => group.children?.includes(w.id));
      const nonMastered = groupWords.filter(w => getReviewState(reviewMap, group, w) !== 'MASTERED');
      const pool = nonMastered.length > 0 ? shuffle(nonMastered) : shuffle(groupWords);
      const activeWord = pool[0] || null;

      set({ activeGroup: group, activeWord, isShowingDefinition: false });
    },

    revealDefinition: () => set({ isShowingDefinition: true }),

    markWord: (known) => {
      const { activeGroup, activeWord, reviewMap } = get();
      if (!activeGroup || !activeWord) return;

      const reviewId = getReviewId(activeGroup, activeWord);
      const currentState = reviewMap[reviewId] || 'NEW';
      const currentIdx = REVIEW_STATES.indexOf(currentState);

      let newState;
      if (known) {
        newState = currentState === 'NEW' ? 'MASTERED' : REVIEW_STATES[Math.min(currentIdx + 1, REVIEW_STATES.length - 1)];
      } else {
        newState = 'LEARNING4';
      }

      const updatedReviewMap = { ...reviewMap, [reviewId]: newState };
      set({ reviewMap: updatedReviewMap });
      get().gotoNextWord(updatedReviewMap);
    },

    gotoNextWord: (updatedReviewMap) => {
      const { activeGroup, activeWord, allWords } = get();
      const reviewMap = updatedReviewMap || get().reviewMap;
      if (!activeGroup) return;

      const groupWords = allWords.filter(w => activeGroup.children?.includes(w.id));
      const nonMastered = groupWords.filter(w => getReviewState(reviewMap, activeGroup, w) !== 'MASTERED');

      let pool = nonMastered.length > 0 ? nonMastered : groupWords;
      pool = shuffle(pool.filter(w => w.id !== activeWord?.id));
      if (pool.length === 0) pool = groupWords;

      set({ activeWord: pool[0] || activeWord, isShowingDefinition: false });
    },

    resetGroup: (groupId) => {
      const { groupsMap, allWords, reviewMap } = get();
      const group = groupsMap[groupId];
      if (!group) return;

      const groupWords = allWords.filter(w => group.children?.includes(w.id));
      const updatedReviewMap = { ...reviewMap };
      groupWords.forEach(w => {
        delete updatedReviewMap[getReviewId(group, w)];
      });
      set({ reviewMap: updatedReviewMap });
    },

    getGroupProgress: (groupId) => {
      const { groupsMap, allWords, reviewMap } = get();
      const group = groupsMap[groupId];
      if (!group) return { new: 0, learning: 0, mastered: 0, total: 0 };
      return computeProgress(group, allWords, reviewMap);
    },

    getGroupWords: (groupId) => {
      const { groupsMap, allWords } = get();
      const group = groupsMap[groupId];
      if (!group) return [];
      return allWords.filter(w => group.children?.includes(w.id));
    },

    getBookmarkedWords: () => {
      const { allWords, bookMarkMap } = get();
      return allWords
        .filter(w => bookMarkMap[w.id])
        .sort((a, b) => a.wordText.localeCompare(b.wordText));
    },

    getMasteredWords: () => {
      const { allWords, groups, reviewMap } = get();
      const mastered = new Set();
      for (const word of allWords) {
        for (const group of groups) {
          if (group.children?.includes(word.id)) {
            const state = reviewMap[getReviewId(group, word)] || 'NEW';
            if (state === 'MASTERED') mastered.add(word.id);
          }
        }
      }
      return allWords.filter(w => mastered.has(w.id));
    },
  }),
  {
    name: 'vocab-store',
    partialize: (state) => ({
      reviewMap: state.reviewMap,
      bookMarkMap: state.bookMarkMap,
      preferredLanguage: state.preferredLanguage,
      dataVersion: state.dataVersion,
    }),
  }
);

const useVocabStore = create(persistedStore);
export default useVocabStore;
