import { useState, useEffect } from 'react';
import Paper from '@mui/material/Paper';
import Box from '@mui/material/Box';
import Avatar from '@mui/material/Avatar';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import IconButton from '@mui/material/IconButton';
import CloseIcon from '@mui/icons-material/Close';
import DownloadIcon from '@mui/icons-material/Download';

const slideUp = 'slideUp 0.3s ease-out';

/**
 * Shows a bottom banner prompting the user to install the app.
 * Uses the `beforeinstallprompt` event (Chrome/Android).
 * On iOS/Safari (which doesn't fire that event) we show manual instructions.
 */
export default function InstallPrompt() {
  const [deferredPrompt, setDeferredPrompt] = useState(null);
  const [showBanner, setShowBanner] = useState(false);
  const [isIOS, setIsIOS] = useState(false);

  useEffect(() => {
    // Don't show if already running as installed PWA
    if (window.matchMedia('(display-mode: standalone)').matches) return;
    // Don't show if user already dismissed
    if (sessionStorage.getItem('pwa-prompt-dismissed')) return;

    const ios = /iphone|ipad|ipod/i.test(navigator.userAgent) && !window.MSStream;
    setIsIOS(ios);

    if (ios) {
      const timer = setTimeout(() => setShowBanner(true), 3000);
      return () => clearTimeout(timer);
    }

    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
      setShowBanner(true);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const dismiss = () => {
    sessionStorage.setItem('pwa-prompt-dismissed', '1');
    setShowBanner(false);
  };

  const install = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setShowBanner(false);
    setDeferredPrompt(null);
  };

  if (!showBanner) return null;

  return (
    <Paper
      elevation={4}
      sx={{
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 1300,
        p: 2,
        display: 'flex',
        alignItems: 'flex-start',
        gap: 2,
        borderTop: '2px solid',
        borderColor: 'primary.light',
        animation: slideUp,
        borderRadius: 0,
      }}
    >
      <Avatar sx={{ bgcolor: 'primary.main' }}>
        <DownloadIcon />
      </Avatar>

      <Box sx={{ flex: 1 }}>
        <Typography variant="subtitle2">Add to Home Screen</Typography>
        {isIOS ? (
          <Typography variant="caption" color="text.secondary">
            Tap <strong>Share</strong> then <strong>&ldquo;Add to Home Screen&rdquo;</strong> for the full-screen app experience.
          </Typography>
        ) : (
          <Typography variant="caption" color="text.secondary">
            Install Deep Vocab for an immersive, offline-capable experience.
          </Typography>
        )}
      </Box>

      {!isIOS && (
        <Button variant="contained" size="small" color="primary" onClick={install}>
          Install
        </Button>
      )}
      <IconButton size="small" onClick={dismiss}>
        <CloseIcon fontSize="small" />
      </IconButton>
    </Paper>
  );
}
