import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Chip from '@mui/material/Chip';

export default function WordDefinition({ definitions }) {
  if (!definitions?.length) return null;

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
      {definitions.map((def, i) => (
        <Box key={i}>
          <Chip
            label={def.type}
            size="small"
            sx={{ fontStyle: 'italic', fontWeight: 700, mb: 0.5, height: 22, fontSize: '0.75rem' }}
          />
          <Typography variant="body2" color="text.primary" sx={{ mt: 0.5 }}>
            {def.definitionText}
          </Typography>

          {def.examples?.length > 0 && (
            <Box sx={{ mt: 1 }}>
              <Typography variant="overline" color="text.secondary" sx={{ lineHeight: 1.5 }}>
                Examples
              </Typography>
              <Box component="ul" sx={{ pl: 2, mt: 0.5, mb: 0 }}>
                {def.examples.map((ex, j) => (
                  <Typography key={j} component="li" variant="body2" color="text.secondary">
                    {ex}
                  </Typography>
                ))}
              </Box>
            </Box>
          )}

          {def.synonyms?.length > 0 && (
            <Box sx={{ mt: 1 }}>
              <Typography variant="overline" color="text.secondary" sx={{ lineHeight: 1.5 }}>
                Synonyms
              </Typography>
              <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
                {def.synonyms.join(', ')}
              </Typography>
            </Box>
          )}
        </Box>
      ))}
    </Box>
  );
}
