import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Box from '@mui/material/Box';
import Card from '@mui/material/Card';
import CardActionArea from '@mui/material/CardActionArea';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import Dialog from '@mui/material/Dialog';
import DialogTitle from '@mui/material/DialogTitle';
import DialogContent from '@mui/material/DialogContent';
import DialogContentText from '@mui/material/DialogContentText';
import DialogActions from '@mui/material/DialogActions';
import ChevronRightIcon from '@mui/icons-material/ChevronRight';
import useVocabStore from '../store/useVocabStore';
import AppBar from '../components/AppBar';
import ProgressChart from '../components/ProgressChart';
import { BRAND_GRADIENT } from '../theme/theme.js';
import { useThemeMode } from '../theme/ThemeContext.jsx';

// pink[A100] on dark (stands out on #121212), red on light
const RESET_COLOR = { light: '#D32F2F', dark: '#ff80ab' };

export default function SubGroupsScreen() {
  const { globalGroupId } = useParams();
  const navigate = useNavigate();
  const globalGroups = useVocabStore(s => s.globalGroups);
  const groupsMap = useVocabStore(s => s.groupsMap);
  const getGroupProgress = useVocabStore(s => s.getGroupProgress);
  const setActiveGroup = useVocabStore(s => s.setActiveGroup);
  const resetGroup = useVocabStore(s => s.resetGroup);
  const [confirmReset, setConfirmReset] = useState(null);
  const { mode } = useThemeMode();
  const resetColor = RESET_COLOR[mode];

  const globalGroup = globalGroups.find(g => g.id === globalGroupId);
  if (!globalGroup) {
    return (
      <Box sx={{ p: 4, color: 'text.secondary' }}>Group not found.</Box>
    );
  }

  const subGroupIds = globalGroup.subGroupIds || [];

  function handleStudy(groupId) {
    setActiveGroup(groupId);
    navigate(`/study/${groupId}`);
  }

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: 'background.default', display: 'flex', flexDirection: 'column' }}>
      <AppBar title={globalGroup.displayName} onBack={() => navigate(-1)} />
      <Box sx={{ flex: 1, p: 2, maxWidth: 600, mx: 'auto', width: '100%', display: 'flex', flexDirection: 'column', gap: 1.5 }}>
        {subGroupIds.map(groupId => {
          const group = groupsMap[groupId];
          if (!group) return null;
          const progress = getGroupProgress(groupId);
          const allMastered = progress.mastered === progress.total && progress.total > 0;
          const toMaster = progress.total - progress.mastered;

          return (
            <Card key={groupId} sx={{ overflow: 'hidden' }}>
              <CardActionArea onClick={() => handleStudy(groupId)}>
                <Box sx={{ height: 4, background: BRAND_GRADIENT }} />
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, p: 2 }}>
                  <ProgressChart progress={progress} size={80} />
                  <Box sx={{ flex: 1, minWidth: 0 }}>
                    <Typography variant="subtitle1" fontWeight={600}>
                      {group.displayName}
                    </Typography>
                    <Typography
                      variant="body2"
                      color={allMastered ? 'success.main' : 'text.secondary'}
                      fontWeight={allMastered ? 600 : 400}
                    >
                      {allMastered
                        ? `Mastered all ${progress.total} words`
                        : `${toMaster} of ${progress.total} words to be mastered`}
                    </Typography>
                  </Box>
                  <ChevronRightIcon color="action" />
                </Box>
              </CardActionArea>
              <Box sx={{ display: 'flex', justifyContent: 'flex-end', px: 2, pb: 1 }}>
                <Button
                  size="small"
                  sx={{ color: resetColor }}
                  onClick={e => { e.stopPropagation(); setConfirmReset(groupId); }}
                >
                  Reset
                </Button>
              </Box>
            </Card>
          );
        })}
      </Box>

      <Dialog
        open={!!confirmReset}
        onClose={() => setConfirmReset(null)}
        maxWidth="xs"
        fullWidth
      >
        <DialogTitle>Reset Progress</DialogTitle>
        <DialogContent>
          <DialogContentText>
            Reset all word progress in &ldquo;{groupsMap[confirmReset]?.displayName}&rdquo; back to NEW?
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setConfirmReset(null)} color="inherit">Cancel</Button>
          <Button
            onClick={() => { resetGroup(confirmReset); setConfirmReset(null); }}
            variant="contained"
            sx={{ bgcolor: resetColor, '&:hover': { bgcolor: resetColor, filter: 'brightness(0.9)' } }}
          >
            Reset
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}
