import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import MuiAppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import IconButton from '@mui/material/IconButton';
import InputBase from '@mui/material/InputBase';
import Box from '@mui/material/Box';
import List from '@mui/material/List';
import ListItemButton from '@mui/material/ListItemButton';
import ListItemText from '@mui/material/ListItemText';
import ListItemSecondaryAction from '@mui/material/ListItemSecondaryAction';
import Typography from '@mui/material/Typography';
import Dialog from '@mui/material/Dialog';
import DialogTitle from '@mui/material/DialogTitle';
import DialogContent from '@mui/material/DialogContent';
import useMediaQuery from '@mui/material/useMediaQuery';
import { useTheme } from '@mui/material/styles';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import SearchIcon from '@mui/icons-material/Search';
import CloseIcon from '@mui/icons-material/Close';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import BookmarkBorderIcon from '@mui/icons-material/BookmarkBorder';
import useVocabStore from '../store/useVocabStore';
import WordDefinition from '../components/WordDefinition';
import { BRAND } from '../theme/theme.js';

export default function SearchScreen() {
  const navigate = useNavigate();
  const [query, setQuery] = useState('');
  const [selectedWord, setSelectedWord] = useState(null);
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down('sm'));

  const getMasteredWords = useVocabStore(s => s.getMasteredWords);
  const toggleBookmark = useVocabStore(s => s.toggleBookmark);
  const bookMarkMap = useVocabStore(s => s.bookMarkMap);
  const preferredLanguage = useVocabStore(s => s.preferredLanguage);

  const mastered = getMasteredWords();
  const filtered = query.trim()
    ? mastered.filter(w => w.wordText.toLowerCase().includes(query.toLowerCase()))
    : mastered;

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: 'background.default', display: 'flex', flexDirection: 'column' }}>
      {/* Custom search AppBar */}
      <MuiAppBar position="static">
        <Toolbar sx={{ gap: 1 }}>
          <IconButton
            edge="start"
            color="inherit"
            onClick={() => navigate(-1)}
            aria-label="Go back"
          >
            <ArrowBackIcon />
          </IconButton>
          <InputBase
            autoFocus
            value={query}
            onChange={e => setQuery(e.target.value)}
            placeholder="Search mastered words…"
            sx={{
              flex: 1,
              bgcolor: 'rgba(255,255,255,0.25)',
              borderRadius: 2,
              px: 1.5,
              py: 0.5,
              color: 'white',
              '& input': { color: 'white' },
              '& input::placeholder': { color: 'rgba(255,255,255,0.7)', opacity: 1 },
            }}
            startAdornment={<SearchIcon sx={{ color: 'rgba(255,255,255,0.8)', mr: 0.5, fontSize: 20 }} />}
          />
          {query && (
            <IconButton color="inherit" size="small" onClick={() => setQuery('')}>
              <CloseIcon fontSize="small" />
            </IconButton>
          )}
        </Toolbar>
      </MuiAppBar>

      <Box sx={{ flex: 1, maxWidth: 600, mx: 'auto', width: '100%' }}>
        {filtered.length === 0 ? (
          <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: 256, gap: 1.5, color: 'text.disabled' }}>
            <SearchIcon sx={{ fontSize: 48, opacity: 0.4 }} />
            <Typography color="text.disabled">
              {mastered.length === 0 ? 'No mastered words yet.' : 'No results found.'}
            </Typography>
          </Box>
        ) : (
          <List disablePadding>
            {filtered.map(word => {
              const isBookmarked = bookMarkMap[word.id];
              return (
                <ListItemButton
                  key={word.id}
                  onClick={() => setSelectedWord(word)}
                  divider
                  sx={{ bgcolor: 'background.paper' }}
                >
                  <ListItemText
                    primary={
                      <Typography variant="subtitle1" fontWeight={600}>
                        {word.wordText}
                      </Typography>
                    }
                  />
                  <ListItemSecondaryAction>
                    <IconButton
                      edge="end"
                      color={isBookmarked ? 'warning' : 'default'}
                      onClick={e => { e.stopPropagation(); toggleBookmark(word); }}
                    >
                      {isBookmarked ? <BookmarkIcon /> : <BookmarkBorderIcon />}
                    </IconButton>
                  </ListItemSecondaryAction>
                </ListItemButton>
              );
            })}
          </List>
        )}
      </Box>

      {/* Word Detail Dialog */}
      <Dialog
        open={!!selectedWord}
        onClose={() => setSelectedWord(null)}
        fullWidth
        maxWidth="sm"
        fullScreen={fullScreen}
      >
        {selectedWord && (
          <>
            <DialogTitle sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <Typography variant="h6" fontWeight={700}>{selectedWord.wordText}</Typography>
              <IconButton size="small" onClick={() => setSelectedWord(null)}>
                <CloseIcon />
              </IconButton>
            </DialogTitle>
            <DialogContent dividers>
              {selectedWord.definitions?.[0]?.otherLanguages?.[preferredLanguage] && (
                <Typography fontWeight={500} sx={{ color: BRAND.accent, mb: 1.5 }}>
                  {selectedWord.definitions[0].otherLanguages[preferredLanguage]}
                </Typography>
              )}
              <WordDefinition definitions={selectedWord.definitions} />
            </DialogContent>
          </>
        )}
      </Dialog>
    </Box>
  );
}
